const original = $node['Webhook Ingest'].json.body?.items || $node['Webhook Ingest'].json.items || [];
const aiRaw = $node['LLM Analyze'].json.choices?.[0]?.message?.content || '{}';
let ai = { items: [] };
try { ai = JSON.parse(aiRaw); } catch {}
const aiMap = new Map((ai.items || []).map(x => [String(x.source_id || ''), x]));

const records = original.slice(0, 200).map((x) => {
  const sid = String(x.source_id || '');
  const isHn = sid.startsWith('hn:');
  const hnId = isHn ? sid.replace('hn:', '') : '';
  const m = aiMap.get(sid) || {};
  return {
    fields: {
      title: String(x.title || ''),
      url: String(x.url || ''),
      score: Number(x.score || 0),
      author: String(x.author || ''),
      published_at: String(x.published_at || ''),
      hn_comments: isHn ? `https://news.ycombinator.com/item?id=${hnId}` : '',
      source: String(x.source_name || x.source || ''),
      summary_cn: String(m.summary_cn || ''),
      tags: String(m.tags || ''),
      stance: String(m.stance || '')
    }
  };
});

return [{ json: { records, count: records.length } }];
